class Solution:
	def solve(self):
		n, m, b, k = [int(x) for x in input().split(' ')]
		dp = [[0] * (m + 1) for _ in range(n + 1)]
		for i in range(1, n + 1):
			for j in range(1, m + 1):
				dp[i][j] = dp[i - 1][j]
				if i >= j:
					dp[i][j] = max(dp[i][j], dp[i - j][j] + j * (b - dp[i - j][j]))
		max_hats = max(dp[i][j] for i in range(1, n + 1) for j in range(1, m + 1))
		print(max_hats)
if __name__ == '__main__':
